  9→interface PostCardProps {
 10→  title: string;
 11→  bodyPreview: string;
 12→  authorName: string;
 13→  authorAvatar?: string | null;
 14→  authorBadge?: 'legend' | 'og' | null;
 15→  bannerImage?: string | null;
 16→  postType?: string;
 17→  readingTime?: string;
 18→  likeCount: number;
 19→  commentCount: number;
 20→  bookmarkCount?: number;
 21→  isLiked?: boolean;
 22→  isBookmarked?: boolean;
 23→  onPress?: () => void;
 24→  onLike?: () => void;
 25→  onComment?: () => void;
 26→  onBookmark?: () => void;
 27→  onRepost?: () => void;
 28→}
 29→
 30→export function PostCard({
 31→  title,
 32→  bodyPreview,
 33→  authorName,
 34→  authorAvatar,
 35→  authorBadge,
 36→  bannerImage,
 37→  postType,
 38→  readingTime,
 39→  likeCount,
 40→  commentCount,
 41→  bookmarkCount,
 42→  isLiked,
 43→  isBookmarked,
 44→  onPress,
 45→  onLike,
 46→  onComment,
 47→  onBookmark,
 48→  onRepost,
 49→}: PostCardProps) {
 50→  const {colors} = useTheme();
 51→  const s = shadows(colors);
 52→
 53→  return (
 54→    <Pressable
 55→      onPress={onPress}
 56→      style={({pressed}) => [
 57→        styles.card,
 58→        {
 59→          backgroundColor: colors.bgCard,
 60→          borderColor: colors.borderCard,
 61→        },
 62→        s.card,
 63→        pressed && styles.pressed,
 64→      ]}>
 65→      {bannerImage ? (
 66→        <Image
 67→          source={{uri: bannerImage}}
 68→          style={styles.banner}
 69→          resizeMode="cover"
 70→        />
 71→      ) : null}
 72→
 73→      <View style={styles.content}>
 74→        {/* Author row */}
 75→        <View style={styles.authorRow}>
 76→          <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
 77→          <Text
 78→            style={[styles.authorName, {color: colors.textSecondary}]}
 79→            numberOfLines={1}>
 80→            {authorName}
 81→          </Text>
 82→          {postType && postType !== 'journal' ? (
 83→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
 84→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
 85→                {postType}
 86→              </Text>
 87→            </View>
 88→          ) : null}
 89→          {readingTime ? (
 90→            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
 91→              <Text style={[styles.typeText, {color: colors.accentSage}]}>
 92→                {readingTime}
 93→              </Text>
 94→            </View>
 95→          ) : null}
 96→        </View>
 97→
 98→        {/* Title */}
 99→        <Text
100→          style={[styles.title, {color: colors.textHeading}]}
101→          numberOfLines={2}>
102→          {title}
103→        </Text>
104→
105→        {/* Body preview */}
106→        {bodyPreview ? (
107→          <Text
108→            style={[styles.body, {color: colors.textBody}]}
109→            numberOfLines={3}>
110→            {bodyPreview}
111→          </Text>
112→        ) : null}
113→      </View>
114→
115→      <ActionBar
116→        likeCount={likeCount}
117→        commentCount={commentCount}
118→        bookmarkCount={bookmarkCount}
119→        isLiked={isLiked}
120→        isBookmarked={isBookmarked}
121→        onLike={onLike}
122→        onComment={onComment}
123→        onBookmark={onBookmark}
124→        onRepost={onRepost}
125→      />
126→    </Pressable>
127→  );
128→}
