 38→const extractPlainText = (rawContent: string | null | undefined): string => {
 39→  if (!rawContent) return '';
 40→  try {
 41→    const parsed = JSON.parse(rawContent) as {
 42→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
 43→    };
 44→    const parts: string[] = [];
 45→    parsed.root?.children?.forEach(node => {
 46→      node.children?.forEach(child => {
 47→        if (child.text) parts.push(child.text);
 48→      });
 49→    });
 50→    return parts.join(' ').replace(/\s+/g, ' ').trim();
 51→  } catch {
 52→    return rawContent.replace(/\s+/g, ' ').trim();
 53→  }
 54→};
