 56→const extractBannerImage = (
 57→  rawContent: string | null | undefined,
 58→  images?: string | string[] | null,
 59→): string | null => {
 60→  // Check images field first
 61→  if (images) {
 62→    if (typeof images === 'string') {
 63→      try {
 64→        const parsed = JSON.parse(images);
 65→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
 66→      } catch {
 67→        if (images.startsWith('http')) return images;
 68→      }
 69→    }
 70→    if (Array.isArray(images) && images.length > 0) return images[0];
 71→  }
 72→  // Try to find image node in Lexical content
 73→  if (!rawContent) return null;
 74→  try {
 75→    const parsed = JSON.parse(rawContent);
 76→    const findImage = (node: any): string | null => {
 77→      if (node.type === 'image' && node.src) return node.src;
 78→      if (node.children) {
 79→        for (const child of node.children) {
 80→          const found = findImage(child);
 81→          if (found) return found;
 82→        }
 83→      }
 84→      return null;
 85→    };
 86→    return findImage(parsed.root ?? parsed);
 87→  } catch {
 88→    return null;
 89→  }
 90→};
